//  DFScrips, a Quippy cypher querry class, returns a streams.sink.topic.cypher.s12 result set.
//  The querry has N,MaxN,Dimension, twoSeq as parameters. 
//  Return rows are calculated, then populate a DataFrame.
//  a iterates over dimension          n iterates over range                   b iterates over tConstraint

object QuerryS3T {

import zadscripts.DFScripts
import scala.collection.mutable.ArrayBuffer
import scala.math.BigDecimal
import org.apache.spark.sql.types.DecimalType
// case class s3T(dimension:String,Degree:Int,scalar:BigDecimal,index:String,maxIndex:BigDecimal,divisor:BigDecimal,rowCounter:String,result:String)
//  val terms = new ArrayBuffer[s3T]()

  def s3TQuerry(rLow:String,rHigh:String,nMax:String,d1:String,d2:String,d3:String,tC:Int): String  = {
  val terms = new ArrayBuffer[s3T]()
  val s3 = new DFScripts  
  val s3RS = s3.s3T(rLow,rHigh,nMax,d1,d2,d3,tC)
  while (s3RS.next()) {                            //  maybe shoud be a map.
  val scalar = BigDecimal(s3RS.getString(3))
  val degree = s3RS.getString(2).toInt
  val divisor = BigDecimal(s3RS.getString(6))
  val index = BigDecimal(s3RS.getString(5))
  val indexPower = index.pow(degree)
  val scalarDiv = scalar/divisor
  val result =  indexPower * scalarDiv
  //print(result + "    ")
  terms += s3T(s3RS.getString(1),degree,scalar,s3RS.getString(4),index,divisor,s3RS.getString(7),result.bigDecimal.toPlainString)
  }
  val termsSeq = terms.toSeq
  //println(termsSeq)
  val resultSeq = termsSeq.map(_.result)           
  val resultSeqBD = resultSeq.collect{ case x:String => BigDecimal(x) }
  //println(resultSeqBD)                              
  resultSeqBD.reduce(_+_).bigDecimal.toPlainString
}

